sql:
SELECT tech_tag
FROM tech_tags
WHERE website_id = 1;

SELECT name
FROM technologies
WHERE website_id = 1;

SELECT COUNT(DISTINCT website_id) AS jpeg_count
FROM content_types
WHERE type = 'image' AND subtype = 'image/jpeg';

SELECT COUNT(DISTINCT method) AS number_of_interactions
FROM methods
WHERE website_id = 1;

SELECT COUNT(website_id) AS nginx_websites_count
FROM web_servers
WHERE name = 'Nginx';

SELECT COUNT(a_tag_id) AS a_tag_count
FROM a_tags
WHERE website_id = 0;

SELECT last_updated
FROM websites
WHERE website_id = 1;

SELECT COUNT(DISTINCT type) AS content_type_count
FROM content_types
WHERE website_id = 1;

SELECT COUNT(certificate_id) AS total_certificates
FROM tls_certificates
WHERE website_id = 1;

SELECT COUNT(*) AS website_count
FROM websites
WHERE status_code = 200 AND tls_tls_version = 'TLS 1.3';

external_knowledge:
Main website refers to the website with the unique identifier 0; 
Typical content types include text, image, and video; 
Subtypes provide more specific information, such as text/html for text content.

